module top_module(
    input [15:0] in,
    output reg [3:0] zeroes_count
);integer i;
    always @(*) begin
        zeroes_count = 0;
        for (i = 0; i < 16; i = i + 1) begin
            if (in[i] == 1'b1) begin
                zeroes_count = zeroes_count + 1;
            end
        end
    end
endmodule
